mapper.select:
SELECT l.*,
       sa.sales_name AS sales_name_join,
       ch.channel_name AS channel_name_join
  FROM jst_sales_commission_ledger l
  LEFT JOIN jst_sales sa ON l.sales_id = sa.sales_id
  LEFT JOIN jst_channel ch ON l.channel_id = ch.channel_id AND ch.del_flag = '0'

    AND l.sales_id = #{salesId}
    AND l.channel_id = #{channelId}
    AND l.status = #{status}
    AND l.settlement_id = #{settlementId}
    AND l.business_type = #{businessType}

ORDER BY l.create_time DESC

mapper.update:
UPDATE jst_sales_commission_ledger
sales_id = #{salesId}, order_id = #{orderId}, order_no = #{orderNo}, channel_id = #{channelId}, binding_type = #{bindingType}, business_type = #{businessType}, base_amount = #{baseAmount}, applied_rate = #{appliedRate}, raw_amount = #{rawAmount}, compress_ratio = #{compressRatio}, amount = #{amount}, status = #{status}, accrue_at = #{accrueAt}, accrued_at = #{accruedAt}, settlement_id = #{settlementId}, update_time = NOW()
WHERE ledger_id = #{ledgerId}

mapper.select:
SELECT  FROM jst_sales_commission_ledger
 WHERE sales_id = #{salesId} AND status = 'accrued'
   AND accrued_at >= #{periodStart} AND accrued_at < #{periodEnd}

SELECT business_type AS businessType, COUNT(*) AS orderCount, COALESCE(SUM(base_amount), 0) AS gmv, COALESCE(SUM(amount), 0) AS commission FROM jst_sales_commission_ledger
AND sales_id = #{salesId} AND create_time >= #{periodStart} AND create_time < #{periodEnd}
GROUP BY business_type
